VALUES
  ('bookkeeper-moex-01222', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '在其他條件不變下，大名企業產品每單位售價為$150，每單位變動製造成本$50，固定製造成本$500,000， 每單位變動行銷成本$40，固定行銷成本$100,000。請問大名企業的損益兩平點銷售單位為多少？', '["4,000單位", "5,000單位", "8,333單位", "10,000單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01223', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '大成企業10月1日預付一年產物保險費$24,000，當天會計入帳時以保險費入帳。請問12月31日有關此 一筆調整分錄，下列敘述何者正確？', '["借記保險費$6,000", "借記預付保險費$18,000", "貸記保險費$6,000", "貸記預付保險費$18,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01224', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '小明在編製試算表時發現借方餘額比貸方餘額多出$90，如果小明過帳時只有發生一項錯誤，下列何者最 可能為小明發生之錯誤？', '["過帳時將一筆借方$90的金額，誤過入貸方項目", "過帳時將一筆$20,090的金額，貸方誤記為$20,009", "過帳時將一筆$18,540的金額，貸方誤記為$18,450", "將一筆賒購進貨$90的交易，誤記成現金交易"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01225', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丁公司於X4年度之普通股流通在外股數之相關資料如下：1月1日1,000股，3月1日增資發行500 股，5月1日發放股票股利20%，11月1日買回庫藏股300股。請問丁公司進行每股盈餘之計算時，X4 年度加權平均流通在外之普通股股數為：', '["1,500股", "1,567股", "1,650股", "2,100股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01226', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丁公司於X3年1月1日簽發一張面額$100,000，票面利率為10%，每年12月31日付息之3年期票據進 行借款，簽發當時之市場利率為12%。此票據於X4年12月31日之餘額應為〔註：⑴複利現值請四捨五 入後，以小數點後五位數為計算基礎；⑵其他計算之金額請以整數值（元）為表達〕：', '["$95,197", "$96,621", "$98,216", "$100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01227', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '依循國際會計準則第37號「負債準備、或有負債及或有資產」，下列有關「或有負債」之敘述何者錯誤？', '["不得認列或有負債", "因過去事項產生之現時義務，很有可能需要流出具經濟效益之資源以清償該義務", "因過去事項產生之現時義務，該經濟義務之金額無法充分可靠地衡量", "因過去事項產生之可能義務，其存在與否僅能由一個或多個未能完全由企業所控制之不確定未來事項 之發生或不發生加以證實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01228', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '戊公司於X4年12月底因火災造成60%之存貨損失，存貨之相關資料如下： X3 年     X4 年 銷貨淨額  $450,000  $500,000 期初存貨  30,000  28,000 進貨  245,000  340,000 進貨運費  5,000  20,000 期末存貨  28,000  ？ 戊公司於X4年12月底因火災造成之存貨損失數為：', '["$28,000", "$43,200", "$64,800", "$108,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01229', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '根據國際會計準則第41號「農業」，下列何者並非該準則列舉之生物資產？', '["綿羊", "乳牛", "棉花", "人造森林之林木"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01230', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '根據國際會計準則第2 號「存貨」之規範中，對於性質與用途類似之所有存貨，應採用相同之成本公式。 惟下列何者為該準則不允許之成本計算公式？', '["成本個別認定法", "先進先出法", "加權平均成本法", "後進先出法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01231', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丙公司於X1年1月1日購買成本$120,000，估計可使用8年，無殘值之設備一部，公司採用直線法提列 折舊。X3年12月31日設備之使用價值$72,000，淨公允價值為$70,000，X5年12月31日使用價值$36,000， 淨公允價值為$39,000，X6年12月31日使用價值$35,000，淨公允價值為$31,000。請問X6年12月31 日資產負債表之設備餘額為：', '["$26,000", "$30,000", "$31,000", "$35,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
